CODE_EXAMPLE:
public abstract class Handler {
  private Handler _next;
  public Handler SetNext(Handler next) { _next = next; return next; }

  public virtual string Handle(int value) {
    return _next != null ? _next.Handle(value) : "unhandled";
  }
}

public class NegativeHandler : Handler {
  public override string Handle(int value) {
    if (value < 0) return "negative";
    return base.Handle(value);
  }
}

public class ZeroHandler : Handler {
  public override string Handle(int value) {
    if (value == 0) return "zero";
    return base.Handle(value);
  }
}

UNIT_TEST_EXAMPLE:
[TestMethod]
public void Chain_HandlesRequest_ByMatchingHandler() {
  var negative = new NegativeHandler();
  var zero = new ZeroHandler();
  negative.SetNext(zero);

  Assert.AreEqual("negative", negative.Handle(-1));
  Assert.AreEqual("zero", negative.Handle(0));
}

[TestMethod]
public void Chain_ReturnsUnhandled_WhenNoMatch() {
  var negative = new NegativeHandler();
  var zero = new ZeroHandler();
  negative.SetNext(zero);

  Assert.AreEqual("unhandled", negative.Handle(10));
}
